"use client";

import React, { createContext, useContext, useEffect, useMemo, useState } from "react";
import { ChatContextType, ChatMessage, ChatSession } from "../types";

const CHAT_STORAGE_KEY = "bgai_chat_sessions";

const ChatContext = createContext<ChatContextType | undefined>(undefined);

function makeSession(name?: string): ChatSession {
  const now = new Date().toISOString();
  return {
    id: `session_${Date.now()}`,
    title: name || `Sesi Chat ${new Date().toLocaleString()}`,
    createdAt: now,
    updatedAt: now,
    messages: [],
  };
}

export function ChatProvider({ children }: { children: React.ReactNode }) {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>("");

  useEffect(() => {
    const saved = localStorage.getItem(CHAT_STORAGE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved) as ChatSession[];
        setSessions(data);
        if (data.length > 0) {
          setActiveSessionId(data[0].id);
        }
      } catch {
        localStorage.removeItem(CHAT_STORAGE_KEY);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(CHAT_STORAGE_KEY, JSON.stringify(sessions));
  }, [sessions]);

  const createSession = (name?: string) => {
    const s = makeSession(name);
    setSessions((prev) => [s, ...prev]);
    setActiveSessionId(s.id);
  };

  const deleteSession = (sessionId: string) => {
    setSessions((prev) => prev.filter((session) => session.id !== sessionId));
    if (activeSessionId === sessionId) {
      const next = sessions.find((s) => s.id !== sessionId);
      setActiveSessionId(next?.id || "");
    }
  };

  const setActiveSession = (sessionId: string) => {
    if (sessions.some((s) => s.id === sessionId)) {
      setActiveSessionId(sessionId);
    }
  };

  const addMessage = (sessionId: string, payload: Omit<ChatMessage, "id" | "createdAt">) => {
    setSessions((prev) =>
      prev.map((session) => {
        if (session.id !== sessionId) return session;
        const msg: ChatMessage = {
          ...payload,
          id: `${sessionId}_${Date.now()}`,
          createdAt: new Date().toISOString(),
        };
        return {
          ...session,
          updatedAt: new Date().toISOString(),
          messages: [...session.messages, msg],
        };
      })
    );
  };

  const sendMessage = async (text: string) => {
    if (!activeSessionId || !text.trim()) return;

    addMessage(activeSessionId, {
      sessionId: activeSessionId,
      role: "user",
      text,
    });

    await new Promise((resolve) => setTimeout(resolve, 700));

    addMessage(activeSessionId, {
      sessionId: activeSessionId,
      role: "assistant",
      text: `Balasan AI untuk: ${text}`,
    });
  };

  const activeSession = useMemo(
    () => sessions.find((s) => s.id === activeSessionId) || null,
    [sessions, activeSessionId]
  );

  const value: ChatContextType = {
    sessions,
    activeSessionId,
    activeSession,
    createSession,
    setActiveSession,
    addMessage,
    sendMessage,
    deleteSession,
  };

  return <ChatContext.Provider value={value}>{children}</ChatContext.Provider>;
}

export function useChat() {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error("useChat must be used within ChatProvider");
  }
  return context;
}
